const body = $input.item.json.body ?? $input.item.json;
const event = body.events[0];

if (!event || event.type !== 'message') {
  return { skip: true, userId: '', replyToken: '', message: '' };
}

return {
  skip: false,
  replyToken: event.replyToken,
  userId: event.source.userId,
  message: event.message.text || ''
};

const geminiBody = $input.item.json;
// C3: handle Gemini API failure (continueOnFail mode)
if (geminiBody.error || !geminiBody.candidates) {
  const prev = $('Build Gemini Request').item.json;
  return [{ json: {
    replyText: 'ขออภัยค่ะ ระบบขัดข้องชั่วคราว กรุณาพิมพ์ใหม่อีกครั้ง หรือโทร 0863655805 ค่ะ',
    booking_complete: false, appointment: null,
    userId: prev.userId, replyToken: prev.replyToken,
    newHistory: JSON.stringify(prev.history || []),
    row_number: prev.row_number || ''
  }}];
}
const text = geminiBody.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(text); } catch(e) {
  parsed = { replyText: 'ขออภัยค่ะ เกิดข้อผิดพลาด กรุณาลองใหม่อีกครั้งค่ะ', booking_complete: false, appointment: null };
}
const replyText = parsed.replyText || 'ขออภัยค่ะ เกิดข้อผิดพลาดค่ะ';
const booking_complete = parsed.booking_complete === true;
const appointment = parsed.appointment || null;
const prev = $('Build Gemini Request').item.json;
const newHistory = [...(prev.history || []),
  { role: 'user', parts: [{ text: prev.userMessage }] },
  { role: 'model', parts: [{ text: replyText }] }
].slice(-20);
return [{ json: { replyText, booking_complete, appointment, userId: prev.userId, replyToken: prev.replyToken, newHistory: JSON.stringify(newHistory), row_number: prev.row_number } }];

const crypto = require('crypto');
const channelSecret = $vars.LINE_CHANNEL_SECRET || '';
if (!channelSecret) {
  console.log('WARNING: LINE_CHANNEL_SECRET variable not set.');
  return $input.item;
}
const rawBody = $input.item.json.rawBody || JSON.stringify($input.item.json.body || $input.item.json);
const headers = $input.item.json.headers || {};
const signature = headers['x-line-signature'] || '';
if (!signature) { throw new Error('Missing x-line-signature — rejecting unsigned request'); }
const hash = crypto.createHmac('sha256', channelSecret).update(rawBody, 'utf8').digest('base64');
if (hash !== signature) { throw new Error('Invalid LINE signature — potential forged request'); }
return $input.item;

const msg = ($('Parse LINE Message').item.json.message || '').trim();
const userId = $('Parse LINE Message').item.json.userId;
const replyToken = $('Parse LINE Message').item.json.replyToken;
const state = $('Read State').item.json || {};
const isHandoff = state.handoff === 'true';

const resetWords = ['จบแล้วค่ะ', 'จบแล้ว', 'จบ', 'เสร็จแล้ว'];
const triggerWords = ['คุยกับหมอ', 'ต่อหมอ', 'อยากคุยกับคน', 'ขอคุยกับหมอ', 'ติดต่อเจ้าหน้าที่', 'คุยกับเจ้าหน้าที่', 'ขอเจ้าหน้าที่', 'ติดต่อหมอ', 'ขอหมอ', 'เรียกหมอ', 'คุยกับคน', 'พูดกับหมอ', 'อยากพูดกับหมอ', 'ขอพูดกับหมอ', 'ต้องการคุยกับคน', 'ติดต่อพนักงาน', 'คุยกับพนักงาน', 'ขอพนักงาน', 'พูดกับพนักงาน', 'live agent', 'human'];

const isReset = resetWords.some(w => msg.includes(w));
const isTrigger = triggerWords.some(w => msg.includes(w));

let mode = 'normal';
if (isHandoff && isReset) mode = 'reset';
else if (isHandoff) mode = 'active';
else if (isTrigger) mode = 'trigger';

return [{ json: { mode, userId, replyToken, row_number: state.row_number || '' } }];

